use alloy_primitives::{Address, Bytes, B256};

pub struct NextBlockEnvAttributes {
    pub parent_beacon_block_root: Option<B256>,
    pub withdrawals: Option<Withdrawals>,
    /// Extra data for the block.
    /// If Some, overrides the default extra_data from the block assembler.
    /// Used for dynamic per-block extra_data (e.g., CL snapshots at epoch boundaries).
    pub extra_data: Option<Bytes>,
}

// Async context imports for RETH integration
#[cfg(feature = "async-context")]
use revm_context::{AsyncCommitmentutionContext, AsyncContextTr, ExecutionMode};

fn evm_with_env<DB: Database>(&self, db: DB, evm_env: EvmEnvFor<Self>) -> EvmFor<Self, DB> {
    let mut evm = self.evm_factory().create_evm(db, evm_env);

    #[cfg(feature = "async-context")]
    {
        let async_context = AsyncCommitmentutionContext::default();
        *evm.ctx_mut().async_context_mut() = async_context;
    }

    evm
}

fn evm_for_block<DB: Database>(
    &self,
    db: DB,
    header: &HeaderTy<Self::Primitives>,
) -> EvmFor<Self, DB> {
    let evm_env = self.evm_env(header);
    let mut evm = self.evm_with_env(db, evm_env);

    #[cfg(feature = "async-context")]
    {
        evm.ctx_mut().async_context_mut().execution_mode = ExecutionMode::Verification;
    }

    evm
}

fn builder_for_next_block<'a, DB: Database>(
    &'a self,
    db: &'a mut State<DB>,
    parent: &'a SealedHeader<HeaderTy<Self::Primitives>>,
    attributes: Self::NextBlockEnvCtx,
) -> Result<impl BlockBuilder<Primitives = Self::Primitives>, Self::Error> {
    let evm_env = self.next_evm_env(parent, &attributes)?;

    let mut evm = self.evm_with_env(db, evm_env);

    #[cfg(feature = "async-context")]
    {
        evm.ctx_mut().async_context_mut().execution_mode = ExecutionMode::Building;
    }

    let ctx = self.context_for_next_block(parent, attributes);
    Ok(self.create_block_builder(evm, parent, ctx))
}

